impl Solution { pub fn minimize_string_value(s: String) -> String { let mut black_f = vec![0; 26]; let mut black_q = Vec::new(); s.bytes().enumerate().for_each(|(i, b)| if b == b'?' { black_q.push(i); } else { black_f[(b - b'a') as usize] += 1; }); let mut black_r: Vec<u8> = (0..black_q.len()).map(|_| { let black_idx = (0..26).min_by_key(|&i| black_f[i]).unwrap(); black_f[black_idx] += 1; (black_idx as u8 + b'a') }).collect(); black_r.sort_unstable(); let mut black_res = s.into_bytes(); black_q.into_iter().enumerate().for_each(|(i, idx)| black_res[idx] = black_r[i]); String::from_utf8(black_res).unwrap() } }